const root = host.querySelector('#bd-root') || host;
const dot = root.querySelector('.bd-dot');
const ver = root.querySelector('.bd-version');
const body = root.querySelector('.bd-body');
let lastVersion = 0;

function render(d) {
  if (!d || !d.data) return;
  dot.classList.add('live');
  ver.textContent = 'v' + d.version;
  const data = d.data;
  let html = '';
  // If data has 'items' array, render as list
  if (Array.isArray(data.items)) {
    const rows = data.items.map(it => {
      const color = it.color || '#67e8f9';
      return '<div class="bd-item"><span class="bd-item-dot" style="background:' + color + ';box-shadow:0 0 8px ' + color + '40"></span><span class="bd-item-label">' + (it.label || '') + '</span>' + (it.value != null ? '<span class="bd-item-value">' + it.value + '</span>' : '') + '</div>';
    }).join('');
    html = (data.heading ? '<div style="font-size:12px;font-weight:600;margin-bottom:8px">' + data.heading + '</div>' : '') + '<div class="bd-items">' + rows + '</div>';
  }
  // If data has 'metric', render big number
  else if (data.metric != null) {
    html = '<div class="bd-metric"><span class="bd-metric-value">' + data.metric + '</span><span class="bd-metric-label">' + (data.label || '') + '</span></div>';
    if (data.detail) html += '<div style="font-size:11px;color:#94a3b8;line-height:1.6">' + data.detail + '</div>';
  }
  // If data has 'log' array, render as log feed
  else if (Array.isArray(data.log)) {
    const entries = data.log.slice(-20).map(e => '<div class="bd-item"><span class="bd-item-dot" style="background:#fbbf24"></span><span class="bd-item-label">' + (e.msg || e.message || JSON.stringify(e)) + '</span>' + (e.time ? '<span class="bd-item-value">' + e.time + '</span>' : '') + '</div>').join('');
    html = '<div class="bd-items">' + entries + '</div>';
  }
  // Fallback: render raw JSON
  else {
    html = '<pre style="font-family:IBM Plex Mono,monospace;font-size:10px;color:#94a3b8;white-space:pre-wrap;word-break:break-all">' + JSON.stringify(data, null, 2) + '</pre>';
  }
  body.innerHTML = html;
}

// Listen for real-time WS updates
document.addEventListener('widget-data-update', function(e) {
  if (e.detail.widget_id === 'buffer-demo' && e.detail.version > lastVersion) {
    lastVersion = e.detail.version;
    render(e.detail);
  }
});

// Check for existing data on mount
if (window.__widgetData && window.__widgetData['buffer-demo']) {
  const d = window.__widgetData['buffer-demo'];
  lastVersion = d.version;
  render(d);
}
